#![allow(unnecessary_transmutes)]
#![allow(clippy::all)]
#![allow(clippy::pedantic)]
#![allow(clippy::nursery)]

include!(concat!(env!("OUT_DIR"), "/bindings.rs"));

/// The correct Rust type for passing a C `va_list` as a function argument.
///
/// The underlying representation of `va_list` varies by platform:
/// - **Pointers or Structs** (e.g., Windows, macOS, ARM): We can directly use the `va_list` type
///   alias generated by `bindgen`.
/// - **Single-element arrays** (e.g., x86_64 Linux/Android): `va_list` is defined as
///   `__va_list_tag[1]`. In C function arguments, it automatically decays into a pointer (`*mut
///   __va_list_tag`). Using `bindgen`'s array alias directly here would cause type mismatches.
///
/// To resolve this ABI discrepancy, we use conditional compilation:
/// - For x86_64 System V ABI (e.g., Linux/Android x86_64): Use the decayed pointer `*mut
///   __va_list_tag`.
/// - For all other platforms: Use the native `va_list` alias.
#[cfg(not(all(target_arch = "x86_64", not(windows), not(target_os = "uefi"))))]
pub type VaList = va_list;

#[cfg(all(target_arch = "x86_64", not(windows), not(target_os = "uefi")))]
pub type VaList = *mut __va_list_tag;
